INSERT INTO quiz_questions (set_id, question_id, question, options, correct_option_index, explanation, sort_order) VALUES
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_1', '"It''s raining cats and dogs"의 뜻은?', '["고양이와 개가 비를 맞는다","비가 매우 많이 온다","동물이 떨어진다","날씨가 좋다"]', 1, '관용표현: 비가 억수같이 온다.', 1),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_2', '"break the ice"의 뜻은?', '["얼음을 깨다","어색한 분위기를 풀다","실수하다","비밀을 말하다"]', 1, '관용표현: 어색한 분위기를 풀다.', 2),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_3', '"bite the bullet"의 뜻은?', '["총알을 물다","어려운 일을 감내하다","포기하다","거짓말하다"]', 1, '관용표현: 어려운 상황을 감내하다.', 3),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_4', '"cost an arm and a leg"의 뜻은?', '["팔다리를 잃다","매우 비싸다","무료이다","할인되다"]', 1, '관용표현: 엄청나게 비싸다.', 4),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_5', '"once in a blue moon"의 뜻은?', '["보름달이 뜰 때","매우 드물게","매일 밤","한 달에 한 번"]', 1, '관용표현: 매우 드물게.', 5),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_6', 'Had I known earlier, I ___ have helped you.', '["will","would","should","could"]', 1, '도치 가정법: Had + S + p.p., S + would have + p.p.', 6),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_7', 'Not until she left ___ I realize my mistake.', '["do","did","was","had"]', 1, '"Not until" 도치 구문: did + S + V원형.', 7),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_8', '"hit the nail on the head"의 뜻은?', '["못을 박다","정확히 맞추다","실수하다","문제를 해결하다"]', 1, '관용표현: 정곡을 찌르다/정확히 맞추다.', 8),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_9', '"let the cat out of the bag"의 뜻은?', '["고양이를 풀어주다","비밀을 누설하다","실수를 만회하다","도망치다"]', 1, '관용표현: 비밀을 누설하다.', 9),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_10', '"under the weather"의 뜻은?', '["비가 올 때","몸이 좋지 않은","우울한","둘 다 맞음"]', 3, '몸이 좋지 않거나 기분이 안 좋은 상태.', 10),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_11', '"affect"와 "effect"의 차이는?', '["같은 의미","affect=동사, effect=명사","affect=명사, effect=동사","반대말"]', 1, '"affect"는 주로 동사(영향을 미치다), "effect"는 주로 명사(결과/효과).', 11),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_12', '"complement"와 "compliment"의 차이는?', '["같은 의미","complement=보완, compliment=칭찬","complement=칭찬, compliment=보완","발음이 다름"]', 1, '"complement"은 보완/보충, "compliment"은 칭찬.', 12),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_13', 'The report ___ be submitted by Friday. (강한 의무)', '["shall","will","must","may"]', 0, '비즈니스에서 "shall"은 강한 의무/규정을 나타냅니다.', 13),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_14', '"turn a blind eye"의 뜻은?', '["눈을 감다","못 본 척하다","눈이 나쁘다","무시하다"]', 1, '관용표현: 못 본 척하다/모른 척하다.', 14),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_15', '"burn the midnight oil"의 뜻은?', '["기름을 태우다","밤늦게까지 일하다","시간을 낭비하다","새벽에 일어나다"]', 1, '관용표현: 밤늦게까지 공부하거나 일하다.', 15),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_16', 'The project, ___ scope was unclear, failed.', '["which","whose","that","whom"]', 1, '관계대명사 소유격: whose.', 16),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_17', 'The person ___ I spoke is the manager.', '["who","whom","to whom","which"]', 2, '"speak to" + 관계대명사 목적격: to whom.', 17),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_18', '"elicit"와 "illicit"의 차이는?', '["같은 의미","elicit=이끌어내다, illicit=불법의","elicit=불법의, illicit=이끌어내다","반대말"]', 1, '"elicit"은 이끌어내다, "illicit"은 불법의.', 18),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_19', '"in the nick of time"의 뜻은?', '["시간이 없다","아슬아슬하게 제시간에","늦게","시간이 남다"]', 1, '관용표현: 간신히/아슬아슬하게 제때.', 19),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_20', '"the ball is in your court"의 뜻은?', '["공이 코트에 있다","당신이 결정할 차례다","게임이 끝났다","기회를 놓쳤다"]', 1, '관용표현: 이제 당신이 결정할 차례다.', 20),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_21', 'Scarcely had he arrived ___ it started to rain.', '["when","than","before","that"]', 0, '"Scarcely had + S + p.p. + when" 도치 구문.', 21),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_22', 'I would sooner die ___ betray my country.', '["as","that","than","to"]', 2, '"would sooner A than B" = B보다 A하겠다.', 22),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_23', '"red tape"의 뜻은?', '["빨간 테이프","관료주의적 절차","위험 표시","경고"]', 1, '관용표현: 번거로운 관료주의적 절차/형식.', 23),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_24', '"white elephant"의 뜻은?', '["흰 코끼리","값비싸지만 쓸모없는 것","행운","희귀한 것"]', 1, '관용표현: 값비싸지만 쓸모없는 것.', 24),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_25', '"kill two birds with one stone"의 뜻은?', '["새를 잡다","일석이조","난폭하다","모험을 하다"]', 1, '관용표현: 일석이조.', 25),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_26', '"meticulous"의 뜻은?', '["꼼꼼한","무성의한","대담한","거친"]', 0, '"meticulous" = 세심한/꼼꼼한.', 26),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_27', '"ubiquitous"의 뜻은?', '["독특한","어디에나 있는","보이지 않는","거대한"]', 1, '"ubiquitous" = 어디에나 있는/편재하는.', 27),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_28', '"pragmatic"의 뜻은?', '["이론적인","실용적인","비판적인","낙관적인"]', 1, '"pragmatic" = 실용적인.', 28),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_29', '"ambiguous"의 뜻은?', '["명확한","모호한","확실한","간결한"]', 1, '"ambiguous" = 모호한/애매한.', 29),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_30', '"reluctant"의 뜻은?', '["열정적인","마지못해 하는","기꺼이 하는","자발적인"]', 1, '"reluctant" = 마지못해 하는/꺼리는.', 30),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_31', '"spill the beans"의 뜻은?', '["콩을 엎지르다","비밀을 말하다","실수하다","음식을 만들다"]', 1, '관용표현: 비밀을 폭로하다.', 31),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_32', '"the last straw"의 뜻은?', '["마지막 빨대","참을 수 없는 마지막 원인","마지막 기회","최후의 수단"]', 1, '관용표현: 참을 수 없게 만드는 마지막 원인.', 32),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_33', 'She demands that he ___ on time. (가정법 현재)', '["is","be","was","were"]', 1, '"demand/insist/suggest that + S + 동사원형(be)" 가정법 현재.', 33),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_34', 'It is imperative that the report ___ submitted.', '["is","be","was","were"]', 1, '"It is imperative that + S + 동사원형" 가정법 현재.', 34),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_35', '"comprehensive"의 뜻은?', '["이해할 수 있는","포괄적인","간단한","반복되는"]', 1, '"comprehensive" = 포괄적인/종합적인.', 35),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_36', '"unprecedented"의 뜻은?', '["예상된","전례 없는","반복되는","대체 가능한"]', 1, '"unprecedented" = 전례 없는.', 36),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_37', '"exacerbate"의 뜻은?', '["개선하다","악화시키다","설명하다","검사하다"]', 1, '"exacerbate" = 악화시키다.', 37),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_38', '"mitigate"의 뜻은?', '["악화시키다","완화하다","이동하다","모방하다"]', 1, '"mitigate" = 완화하다/경감하다.', 38),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_39', '"corroborate"의 뜻은?', '["부정하다","확증하다/뒷받침하다","부패시키다","협력하다"]', 1, '"corroborate" = 확증하다/뒷받침하다.', 39),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_40', '"juxtapose"의 뜻은?', '["병치하다/나란히 놓다","옮기다","반대하다","분류하다"]', 0, '"juxtapose" = 병치하다/나란히 놓다.', 40),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_41', '"beat around the bush"의 뜻은?', '["숲을 돌다","빙빙 돌려 말하다","숨바꼭질 하다","검색하다"]', 1, '관용표현: 요점을 피하고 빙빙 돌려 말하다.', 41),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_42', '"blessing in disguise"의 뜻은?', '["위장한 축복","전화위복","변장","거짓 약속"]', 1, '관용표현: 전화위복/인 듯 나쁜 것이 결과적으로 좋은 것.', 42),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_43', 'Were it not ___ your help, I would have failed.', '["to","for","by","with"]', 1, '"Were it not for" = ~이 아니었더라면 (도치 가정법).', 43),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_44', '"eloquent"의 뜻은?', '["조용한","유창한/웅변적인","거친","무관심한"]', 1, '"eloquent" = 유창한/웅변적인.', 44),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_45', '"resilient"의 뜻은?', '["약한","회복력 있는","저항하는","유연한"]', 1, '"resilient" = 회복력 있는/탄력적인.', 45),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_46', '"discrepancy"의 뜻은?', '["일치","불일치/차이","구별","차별"]', 1, '"discrepancy" = 불일치/차이/모순.', 46),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_47', '"amenable"의 뜻은?', '["수정 가능한","순응하는/기꺼이 하는","매력적인","적대적인"]', 1, '"amenable" = 순응하는/기꺼이 받아들이는.', 47),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_48', '"a penny for your thoughts"의 뜻은?', '["1페니를 줄게","무슨 생각을 하는지 말해봐","돈이 없다","저렴하다"]', 1, '관용표현: 무슨 생각을 하고 있니?', 48),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_49', '"cut corners"의 뜻은?', '["모서리를 자르다","대충 하다/편법을 쓰다","절약하다","방향을 바꾸다"]', 1, '관용표현: 대충 하다/편법을 쓰다.', 49),
((SELECT id FROM quiz_sets WHERE difficulty='ADVANCED' AND category='english'), 'en_g_50', '"throw in the towel"의 뜻은?', '["수건을 던지다","포기하다","싸우다","도전하다"]', 1, '관용표현: 포기하다/항복하다.', 50)
