INSERT INTO quiz_questions (correct_option_index, created_at, explanation, options, question, question_id, sort_order, set_id) VALUES
-- 1~40: Advanced Context Clues (최상급 어휘 문맥 추론)
(1, CURRENT_TIMESTAMP, '"Obfuscate"는 (의도적으로) 애매하게 하다, 혼란스럽게 하다라는 뜻입니다.', '["elucidate", "obfuscate", "ameliorate", "vindicate"]', 'The politician''s speech was designed to ______ the truth rather than explain it clearly.', 'en_ad_1', 1, 12),
(0, CURRENT_TIMESTAMP, '"Fastidious"는 세심한, 꼼꼼한, 까다로운 이라는 뜻입니다.', '["fastidious", "slovenly", "indolent", "apathetic"]', 'Known for his ______ attention to detail, the watchmaker spent months perfecting a single gear.', 'en_ad_2', 2, 12),
(2, CURRENT_TIMESTAMP, '"Dearth"는 부족, 결핍이라는 뜻입니다.', '["plethora", "surfeit", "dearth", "abundance"]', 'The committee faced a ______ of viable solutions, forcing them to adopt a risky strategy.', 'en_ad_3', 3, 12),
(3, CURRENT_TIMESTAMP, '"Spurious"는 가짜의, 위조의라는 뜻입니다.', '["authentic", "genuine", "verifiable", "spurious"]', 'The journalist was fired after it was discovered that her sources were entirely ______.', 'en_ad_4', 4, 12),
(1, CURRENT_TIMESTAMP, '"Ephemeral"은 수명이 짧은, 단명하는 이라는 뜻입니다.', '["perpetual", "ephemeral", "enduring", "eternal"]', 'The beauty of the cherry blossoms is ______, lasting only a few days before the petals fall.', 'en_ad_5', 5, 12),
(0, CURRENT_TIMESTAMP, '"Sycophant"는 아첨꾼이라는 뜻입니다.', '["sycophant", "maverick", "iconoclast", "misanthrope"]', 'The CEO was surrounded by ______s who agreed with his every decision, no matter how disastrous.', 'en_ad_6', 6, 12),
(2, CURRENT_TIMESTAMP, '"Capricious"는 변덕스러운 이라는 뜻입니다.', '["steadfast", "resolute", "capricious", "unwavering"]', 'Her ______ nature made it impossible to predict what she would do from one moment to the next.', 'en_ad_7', 7, 12),
(1, CURRENT_TIMESTAMP, '"Mitigate"는 완화하다, 경감시키다라는 뜻입니다.', '["exacerbate", "mitigate", "aggravate", "intensify"]', 'The new policies were implemented to ______ the devastating effects of the economic recession.', 'en_ad_8', 8, 12),
(3, CURRENT_TIMESTAMP, '"Quixotic"은 비현실적인, 공상적인 이라는 뜻입니다. (돈키호테에서 유래)', '["pragmatic", "lucid", "cynical", "quixotic"]', 'His ______ plan to solve world hunger with a single invention was met with deep skepticism.', 'en_ad_9', 9, 12),
(0, CURRENT_TIMESTAMP, '"Pernicious"는 치명적인, 해로운 이라는 뜻입니다.', '["pernicious", "benign", "innocuous", "salutary"]', 'The ______ influence of the cult gradually alienated the young man from his family and friends.', 'en_ad_10', 10, 12),
(1, CURRENT_TIMESTAMP, '"Garrulous"는 수다스러운 이라는 뜻입니다.', '["taciturn", "garrulous", "reticent", "laconic"]', 'The ______ passenger next to me talked incessantly for the entire six-hour flight.', 'en_ad_11', 11, 12),
(2, CURRENT_TIMESTAMP, '"Enervate"는 기력을 빼앗다, 약화시키다라는 뜻입니다.', '["invigorate", "galvanize", "enervate", "bolster"]', 'The extreme heat and humidity began to ______ the marathon runners early in the race.', 'en_ad_12', 12, 12),
(0, CURRENT_TIMESTAMP, '"Auspicious"는 길조의, 상서로운 이라는 뜻입니다.', '["auspicious", "ominous", "sinister", "dire"]', 'The successful launch of the satellite was an ______ beginning for the new space program.', 'en_ad_13', 13, 12),
(3, CURRENT_TIMESTAMP, '"Castigate"는 크게 책망하다, 혹평하다라는 뜻입니다.', '["extol", "laud", "eulogize", "castigate"]', 'The strict teacher would often ______ students for making even the smallest grammatical errors.', 'en_ad_14', 14, 12),
(1, CURRENT_TIMESTAMP, '"Alacrity"는 민활함, 기꺼이 함 이라는 뜻입니다.', '["apathy", "alacrity", "lethargy", "sluggishness"]', 'She accepted the prestigious job offer with ______, eager to start her new career immediately.', 'en_ad_15', 15, 12),
(2, CURRENT_TIMESTAMP, '"Pedantic"은 지나치게 규칙을 찾거나 아는 체하는 이라는 뜻입니다.', '["erudite", "insightful", "pedantic", "visionary"]', 'His ______ writing style focused on trivial details rather than the broader themes of the subject.', 'en_ad_16', 16, 12),
(0, CURRENT_TIMESTAMP, '"Ostentatious"는 과시하는, 허세 부리는 이라는 뜻입니다.', '["ostentatious", "unobtrusive", "modest", "subdued"]', 'The billionaire''s ______ mansion featured gold-plated fixtures and marble floors imported from Italy.', 'en_ad_17', 17, 12),
(1, CURRENT_TIMESTAMP, '"Corroborate"는 확증하다, 입증하다라는 뜻입니다.', '["refute", "corroborate", "contradict", "repudiate"]', 'Multiple eyewitness accounts were needed to ______ the victim''s testimony in court.', 'en_ad_18', 18, 12),
(3, CURRENT_TIMESTAMP, '"Exonerate"는 무죄임을 밝히다, 면제하다라는 뜻입니다.', '["indict", "condemn", "incriminate", "exonerate"]', 'DNA evidence emerged years later to completely ______ the man who had been falsely imprisoned.', 'en_ad_19', 19, 12),
