(3, CURRENT_TIMESTAMP, '"make do with"는 ~으로 임시변통하다, 견디다라는 뜻입니다.', '["get", "come", "deal", "make"]', 'Since we don''t have the right tools, we will just have to ______ do with what we have.', 'en_ad_100', 100, 12);

INSERT INTO quiz_questions (correct_option_index, created_at, explanation, options, question, question_id, sort_order, set_id) VALUES
-- 101~140: Advanced Context Clues & Vocabulary (최상급 어휘 및 논리 완성)
(1, CURRENT_TIMESTAMP, '"Assuage"는 (안 좋은 감정을) 달래다, 누그러뜨리다라는 뜻입니다.', '["exacerbate", "assuage", "provoke", "foment"]', 'The company tried to ______ the public''s fear by releasing a detailed safety report.', 'en_ad_101', 101, 12),
(0, CURRENT_TIMESTAMP, '"Esoteric"은 소수만 이해하는, 심오한 이라는 뜻입니다.', '["esoteric", "lucid", "banal", "mundane"]', 'The professor''s lecture on quantum mechanics was so ______ that only a few graduate students could follow it.', 'en_ad_102', 102, 12),
(2, CURRENT_TIMESTAMP, '"Intransigent"는 고집스러운, 타협하지 않는 이라는 뜻입니다.', '["docile", "pliant", "intransigent", "amenable"]', 'Despite hours of negotiation, the union leaders remained ______, refusing to accept the pay cut.', 'en_ad_103', 103, 12),
(3, CURRENT_TIMESTAMP, '"Erudite"는 학식 있는, 박식한 이라는 뜻입니다.', '["ignorant", "obtuse", "frivolous", "erudite"]', 'The ______ scholar could speak seven languages and had read almost every book in the ancient library.', 'en_ad_104', 104, 12),
(0, CURRENT_TIMESTAMP, '"Iconoclast"는 우상 파괴자, 인습 타파주의자라는 뜻입니다.', '["iconoclast", "traditionalist", "conformist", "sycophant"]', 'As an ______, the young director constantly challenged Hollywood''s traditional storytelling methods.', 'en_ad_105', 105, 12),
(1, CURRENT_TIMESTAMP, '"Propriety"는 적절성, 예의범절이라는 뜻입니다.', '["audacity", "propriety", "insolence", "frivolity"]', 'The formal dinner required a strict sense of ______; guests were expected to dress and act impeccably.', 'en_ad_106', 106, 12),
(2, CURRENT_TIMESTAMP, '"Evanescent"는 덧없이 사라지는, 순간적인 이라는 뜻입니다.', '["perpetual", "enduring", "evanescent", "immortal"]', 'A rainbow is ______, appearing beautifully after a storm only to fade away minutes later.', 'en_ad_107', 107, 12),
(3, CURRENT_TIMESTAMP, '"Polemic"은 맹렬한 비판, 논쟁이라는 뜻입니다.', '["eulogy", "panegyric", "tribute", "polemic"]', 'The author''s new book is a fierce ______ against the corruption of the modern political system.', 'en_ad_108', 108, 12),
(0, CURRENT_TIMESTAMP, '"Diffidence"는 자신감 부족, 수줍음이라는 뜻입니다.', '["diffidence", "arrogance", "hubris", "temerity"]', 'Her ______ kept her from speaking up in meetings, even when she had the best ideas.', 'en_ad_109', 109, 12),
(1, CURRENT_TIMESTAMP, '"Diatribe"는 통렬한 비난, 장광설이라는 뜻입니다.', '["encomium", "diatribe", "elegy", "oration"]', 'The coach delivered a bitter ______ to the team after their humiliating defeat.', 'en_ad_110', 110, 12),
(2, CURRENT_TIMESTAMP, '"Euphemism"은 완곡어법이라는 뜻입니다. (예: 죽다 -> 돌아가시다)', '["hyperbole", "oxymoron", "euphemism", "paradox"]', 'Using "passed away" instead of "died" is a common ______ used to soften the blow of grief.', 'en_ad_111', 111, 12),
(3, CURRENT_TIMESTAMP, '"Platitude"는 진부한 이야기, 뻔한 말이라는 뜻입니다.', '["epigram", "aphorism", "maxim", "platitude"]', 'Instead of offering real advice, he just mumbled a ______ about how "time heals all wounds."', 'en_ad_112', 112, 12),
(0, CURRENT_TIMESTAMP, '"Chicanery"는 교묘한 속임수, 발뺌이라는 뜻입니다.', '["chicanery", "candor", "probity", "rectitude"]', 'The corrupt politician used financial ______ to hide his illegal campaign contributions.', 'en_ad_113', 113, 12),
(1, CURRENT_TIMESTAMP, '"Obsequious"는 아부하는, 비굴한 이라는 뜻입니다.', '["imperious", "obsequious", "haughty", "arrogant"]', 'The ______ waiter hovered constantly, hoping his excessive flattery would earn him a large tip.', 'en_ad_114', 114, 12),
(2, CURRENT_TIMESTAMP, '"Inexorable"은 거침없는, 멈출 수 없는 이라는 뜻입니다.', '["pliable", "flexible", "inexorable", "yielding"]', 'The ______ advance of the glacier slowly carved the valley out of the solid rock.', 'en_ad_115', 115, 12),
(3, CURRENT_TIMESTAMP, '"Prescient"는 선견지명이 있는 이라는 뜻입니다.', '["myopic", "oblivious", "hindsight", "prescient"]', 'Her ______ warning about the housing market crash went ignored until it was too late.', 'en_ad_116', 116, 12),
(0, CURRENT_TIMESTAMP, '"Recalcitrant"는 저항하는, 다루기 힘든 이라는 뜻입니다.', '["recalcitrant", "submissive", "compliant", "docile"]', 'The ______ horse refused to be saddled, bucking and kicking whenever anyone approached.', 'en_ad_117', 117, 12),
(1, CURRENT_TIMESTAMP, '"Probity"는 정직성, 청렴결백이라는 뜻입니다.', '["duplicity", "probity", "perfidy", "deceit"]', 'The judge was known for his absolute ______; he could not be bribed or intimidated.', 'en_ad_118', 118, 12),
(2, CURRENT_TIMESTAMP, '"Specious"는 겉만 그럴싸한 이라는 뜻입니다.', '["valid", "cogent", "specious", "sound"]', 'The salesman''s argument sounded convincing at first, but it was based on ______ reasoning.', 'en_ad_119', 119, 12),
(3, CURRENT_TIMESTAMP, '"Tortuous"는 구불구불한, 매우 복잡한 이라는 뜻입니다. (torturous: 고통스러운 과 구별)', '["straightforward", "direct", "linear", "tortuous"]', 'The drive up the mountain involved a ______ road with blind curves and steep drop-offs.', 'en_ad_120', 120, 12),
(0, CURRENT_TIMESTAMP, '"Venal"은 매수되기 쉬운, 부패한 이라는 뜻입니다.', '["venal", "incorruptible", "ethical", "scrupulous"]', 'The country''s economy collapsed due to the actions of ______ politicians who looted the treasury.', 'en_ad_121', 121, 12),
(1, CURRENT_TIMESTAMP, '"Paucity"는 소량, 결핍이라는 뜻입니다.', '["plethora", "paucity", "surfeit", "glut"]', 'Despite the ______ of evidence, the aggressive prosecutor decided to take the case to trial.', 'en_ad_122', 122, 12),
(2, CURRENT_TIMESTAMP, '"Burgeon"은 급성장하다, 번창하다라는 뜻입니다.', '["dwindle", "wither", "burgeon", "stagnate"]', 'Driven by a sudden influx of tech companies, the city''s population began to ______.', 'en_ad_123', 123, 12),
(3, CURRENT_TIMESTAMP, '"Upbraid"는 모질게 꾸짖다라는 뜻입니다.', '["extol", "laud", "commend", "upbraid"]', 'The commanding officer called the soldier into his office to ______ him for leaving his post.', 'en_ad_124', 124, 12),
(0, CURRENT_TIMESTAMP, '"Dogmatic"은 독단적인 이라는 뜻입니다.', '["dogmatic", "open-minded", "receptive", "flexible"]', 'He was so ______ in his political beliefs that he refused to even listen to opposing arguments.', 'en_ad_125', 125, 12),
(1, CURRENT_TIMESTAMP, '"Ebullient"는 패기만만한, 열광적인 이라는 뜻입니다.', '["melancholy", "ebullient", "morose", "despondent"]', 'After winning the championship, the ______ crowd flooded the streets to celebrate.', 'en_ad_126', 126, 12),
(2, CURRENT_TIMESTAMP, '"Punctilious"는 꼼꼼한, 예의범절에 까다로운 이라는 뜻입니다.', '["negligent", "slipshod", "punctilious", "remiss"]', 'The royal butler was ______ in his duties, ensuring every fork was placed exactly an inch from the plate.', 'en_ad_127', 127, 12),
(3, CURRENT_TIMESTAMP, '"Trite"는 진부한, 낡은 이라는 뜻입니다.', '["original", "profound", "innovative", "trite"]', 'The movie''s ending was incredibly ______; we had seen the exact same plot twist a hundred times before.', 'en_ad_128', 128, 12),
(0, CURRENT_TIMESTAMP, '"Insipid"는 맛이 없는, 재미없는 이라는 뜻입니다.', '["insipid", "piquant", "zesty", "flavorful"]', 'Without any spices or salt, the soup tasted completely ______ and unappetizing.', 'en_ad_129', 129, 12),
(1, CURRENT_TIMESTAMP, '"Magnanimous"는 도량이 넓은, 너그러운 이라는 뜻입니다.', '["petty", "magnanimous", "vindictive", "spiteful"]', 'In a ______ gesture, the victor offered to pay for the reconstruction of the defeated city.', 'en_ad_130', 130, 12),
(2, CURRENT_TIMESTAMP, '"Obdurate"는 고집 센, 완고한 이라는 뜻입니다.', '["pliant", "tractable", "obdurate", "malleable"]', 'Despite the pleas of his family, the ______ old man refused to seek medical treatment.', 'en_ad_131', 131, 12),
(3, CURRENT_TIMESTAMP, '"Perfidious"는 믿을 수 없는, 배반하는 이라는 뜻입니다.', '["loyal", "faithful", "staunch", "perfidious"]', 'The king was overthrown not by his enemies, but by his ______ advisors who secretly plotted his downfall.', 'en_ad_132', 132, 12),
(0, CURRENT_TIMESTAMP, '"Querulous"는 불평하는, 짜증내는 이라는 뜻입니다.', '["querulous", "contented", "placid", "serene"]', 'The exhausted flight attendant tried to remain polite while dealing with a highly ______ passenger.', 'en_ad_133', 133, 12),
(1, CURRENT_TIMESTAMP, '"Sagacious"는 현명한, 통찰력 있는 이라는 뜻입니다.', '["foolish", "sagacious", "inane", "fatuous"]', 'The tribal elders were respected for their ______ advice, honed by decades of experience.', 'en_ad_134', 134, 12),
(2, CURRENT_TIMESTAMP, '"Discrepancy"는 불일치, 차이라는 뜻입니다.', '["congruence", "accord", "discrepancy", "harmony"]', 'The auditor noticed a significant ______ between the company''s reported income and its bank statements.', 'en_ad_135', 135, 12),
(3, CURRENT_TIMESTAMP, '"Corollary"는 필연적인 결과, 당연한 귀결이라는 뜻입니다.', '["cause", "origin", "inception", "corollary"]', 'Increased traffic congestion is an inevitable ______ of rapid urban expansion.', 'en_ad_136', 136, 12),
(0, CURRENT_TIMESTAMP, '"Dichotomy"는 이분법, 양분이라는 뜻입니다.', '["dichotomy", "synthesis", "amalgam", "blend"]', 'Her essay explored the strict ______ between nature and civilization in 19th-century literature.', 'en_ad_137', 137, 12),
(1, CURRENT_TIMESTAMP, '"Proclivity"는 성향, 기질이라는 뜻입니다.', '["aversion", "proclivity", "antipathy", "reluctance"]', 'Even as a child, he showed a ______ for music, plucking melodies out on the piano by ear.', 'en_ad_138', 138, 12),
(2, CURRENT_TIMESTAMP, '"Amalgam"은 혼합물, 결합물이라는 뜻입니다.', '["separation", "division", "amalgam", "segregation"]', 'The new architectural style is an ______ of traditional Gothic elements and modern glass designs.', 'en_ad_139', 139, 12),
(3, CURRENT_TIMESTAMP, '"Nadir"는 최악의 순간, 바닥이라는 뜻입니다.', '["zenith", "pinnacle", "apex", "nadir"]', 'Losing his job and his home in the same week represented the absolute ______ of his life.', 'en_ad_140', 140, 12),

-- 141~160: Logic & Conceptual Equivalence (고급 논리 추론 및 개념)
(0, CURRENT_TIMESTAMP, '"Zenith"는 정점, 절정이라는 뜻입니다.', '["zenith", "abyss", "trough", "nadir"]', 'Winning the Nobel Prize was undoubtedly the ______ of the scientist''s long and distinguished career.', 'en_ad_141', 141, 12),
(1, CURRENT_TIMESTAMP, '"Reprieve"는 형 집행 연기, 일시적 구제라는 뜻입니다.', '["condemnation", "reprieve", "sentence", "punishment"]', 'The sudden drop in temperatures provided a much-needed ______ for the firefighters battling the wildfire.', 'en_ad_142', 142, 12),
(2, CURRENT_TIMESTAMP, '"Paradox"는 역설(모순되어 보이지만 사실인 것)이라는 뜻입니다.', '["tautology", "cliche", "paradox", "truism"]', 'It is a strange ______ that the more choices we have, the harder it becomes to make a decision.', 'en_ad_143', 143, 12),
